<?php $data = json_decode(file_get_contents("php://stdin"), true); $events = $data["events"] ?? []; $selected = []; foreach ($events as $event) { if (($event["type"] ?? "") === "btdb_limitedTimeArena") { $selected[] = ["name" => $event["name"] ?? "", "ruleSet" => $event["metadata"]["ruleSetID"] ?? null, "roomTypes" => $event["metadata"]["roomTypes"] ?? []]; if (count($selected) >= 10) break; } } echo json_encode($selected); ?>
